// ============================================================
// 노드 2b: 실시간 환율·코인 가격 수집 (무료 API, 키 불필요)
// - 환율: Frankfurter API (ECB 기준, 무료)
// - 비트코인: CoinGecko API (무료)
// 실패 시 0 반환, 워크플로 중단 안 함
// ============================================================
const prev = $input.first().json;
let usdKrw = 0, btcUsd = 0, btcKrw = 0;

// 1) USD/KRW 환율 (Frankfurter — ECB 기준, 무료)
try {
  const fx = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.frankfurter.app/latest?from=USD&to=KRW',
    timeout: 8000
  });
  usdKrw = fx?.rates?.KRW ? Math.round(fx.rates.KRW) : 0;
} catch(e) {}

// 2) 비트코인 USD·KRW (CoinGecko 무료)
try {
  const btc = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.coingecko.com/api/v3/simple/price?ids=bitcoin&vs_currencies=usd,krw',
    timeout: 8000
  });
  btcUsd = btc?.bitcoin?.usd ? Math.round(btc.bitcoin.usd) : 0;
  btcKrw = btc?.bitcoin?.krw ? Math.round(btc.bitcoin.krw / 10000) * 10000 : 0;
} catch(e) {}

return [{ json: {
  ...prev,
  usdKrw, btcUsd, btcKrw,
  realtimeFetched: (usdKrw > 0 || btcUsd > 0)
}}];

// S03-Perplexity: sonar-pro — 종합 글로벌 금융 브리핑
const inp = $input.first().json;
const { today, obsidianFilePath, backupFilePath, startTime } = inp;
const usdKrw = inp.usdKrw || 0;
const btcUsd  = inp.btcUsd  || 0;
const KEY = $env.PERPLEXITY_API_KEY;

if (!KEY || KEY.includes('여기에')) {
  return [{ json: {
    success: false, source: 'perplexity',
    error: 'PERPLEXITY_API_KEY 미설정',
    rawContent: null,
    today, obsidianFilePath, backupFilePath, startTime, usdKrw, btcUsd
  }}];
}

const systemPrompt = 'You are a senior Wall Street veteran analyst with 30+ years at Goldman Sachs, Bridgewater Associates, and JPMorgan. Expert in global macro, institutional research synthesis, and Korean market impacts.\n\nABSOLUTE RULES:\n1. Every number MUST have source citation (URL or [Publication Name, Date])\n2. If data unverifiable for today, write [미확인] — NEVER fabricate\n3. Cover ALL 6 sections completely\n4. Include legendary investor views (Buffett, Dalio, Burry)\n5. Minimum 5 verified data points per section\n6. Aim for 4000+ words total';

const userPrompt = 'Date: ' + today + ' (KST). Provide comprehensive verified financial morning briefing. CITE source URL for EVERY number.\n\n[SECTION 1: WORLD MARKETS]\nUS Indices (S&P500, NASDAQ, Dow, Russell 2000 exact levels & %). European markets (Stoxx600, DAX, FTSE, CAC). Asian markets (Nikkei, HSI, CSI300, ASX). CNN Fear & Greed index. Top overnight catalyst.\n\n[SECTION 2: US MARKET DEEP]\nAll 11 S&P sectors (XLK,XLF,XLV,XLY,XLP,XLE,XLI,XLB,XLU,XLRE,XLC) % change. NYSE advance/decline. Treasury yields 2Y/10Y/30Y exact% + spread bps. Fed rate/FOMC date/CME FedWatch%. DXY and VIX exact levels.\n\n[SECTION 3: KOREAN MARKET]\nKOSPI exact close & %. KOSDAQ exact & %. Foreign net buy/sell KRW billions. Samsung(005930), SK Hynix(000660), NAVER prices & %. USD/KRW exact, BOK rate, next BOK meeting.\n\n[SECTION 4: CRYPTO & ALTERNATIVES]\nBTC/USD exact + 24h%. ETH/USD exact + 24h%. Total crypto market cap. Gold XAU/USD exact. WTI & Brent exact prices & key driver.\n\n[SECTION 5: GLOBAL MACRO]\nLatest US CPI/PPI/PCE/NFP/unemployment. China PMI/exports/PBOC. ECB/BOJ rate status. EUR/USD, JPY/USD. Active geopolitical risks with market impact.\n\n[SECTION 6: RISK & OPPORTUNITY]\nTop 3 tail risks this week. Top 3 opportunities. Buffett/Dalio/Burry recent views. GS/JPM/BlackRock latest research. Key events next 5 days.';

const rtPrices = [];
if (usdKrw > 0) rtPrices.push('- USD/KRW: EXACTLY ' + usdKrw.toLocaleString() + ' KRW (real-time ECB)');
if (btcUsd  > 0) rtPrices.push('- BTC/USD: EXACTLY $' + btcUsd.toLocaleString() + ' (real-time CoinGecko)');
const verifiedNote = rtPrices.length > 0
  ? '\n\nMANDATORY PRICE OVERRIDE:\n' + rtPrices.join('\n')
  : '';
const finalPrompt = userPrompt + verifiedNote;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.perplexity.ai/chat/completions',
    headers: {
      'Authorization': 'Bearer ' + KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'sonar',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: finalPrompt }
      ],
      temperature: 0.1,
      max_tokens: 6000,
      return_citations: true
    }),
    timeout: 60000
  });

  const r = typeof response === 'string' ? JSON.parse(response) : response;
  const content = r?.choices?.[0]?.message?.content;
  if (!content || content.trim().length < 200)
    throw new Error('응답 부실 (' + (content?.length || 0) + '자)');

  return [{ json: {
    success: true, source: 'perplexity',
    rawContent: content,
    today, obsidianFilePath, backupFilePath, startTime, usdKrw, btcUsd
  }}];
} catch(e) {
  return [{ json: {
    success: false, source: 'perplexity',
    error: e.message,
    rawContent: null,
    today, obsidianFilePath, backupFilePath, startTime, usdKrw, btcUsd
  }}];
}

// S04-GPT-CrossVal: GPT-4o 독립 분석 + 교차검증 정리
const prev = $input.first().json;
const { rawContent, today, obsidianFilePath, backupFilePath, startTime } = prev;
const usdKrw = prev.usdKrw || 0;
const btcUsd  = prev.btcUsd  || 0;
const perpSuccess = prev.success !== false;
const KEY = $env.OPENAI_API_KEY;

const systemPrompt = '당신은 한국 기관투자자를 위한 글로벌 매크로·주식 애널리스트다. 오늘 날짜 기준 독립적으로 분석·요약한다. 사실과 추론을 명확히 구분하고, 각 이슈의 원인→결과 체인을 반드시 연결한다.';

const userPrompt = '오늘: ' + today + ' | USD/KRW: ' + usdKrw + ' | BTC: ' + btcUsd + '\n\n1. 미 증시 요약 (지수·섹터·대표 종목 수익률 표)\n2. 핵심 변화요인 인과 분석 (원인→결과 체인)\n3. 섹터·테마별 임팩트 (반도체/소프트웨어/자동차/온라인소비/비트코인)\n4. 한국 증시 시사점 (환율·반도체·AI규제·개장방향)\n5. FICC 요약\n6. 리스크·기회 체크포인트 3가지\n\n형식: 한국어, Markdown';

let gptContent = null;
let gptSuccess = false;

if (KEY && !KEY.includes('여기에')) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + KEY
      },
      body: JSON.stringify({
        model: 'gpt-4o',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user',   content: userPrompt }
        ],
        temperature: 0.3,
        max_tokens: 3000
      }),
      timeout: 45000
    });
    const r = typeof response === 'string' ? JSON.parse(response) : response;
    if (r?.choices?.[0]?.message?.content) {
      gptContent = r.choices[0].message.content;
      gptSuccess = true;
    }
  } catch (e) {
    // GPT 실패 시 Perplexity 단독 진행
  }
}

return [{ json: {
  rawContent,
  gptContent,
  gptSuccess,
  perpSuccess,
  today, obsidianFilePath, backupFilePath, startTime, usdKrw, btcUsd,
  source: prev.source || 'perplexity',
  newsSource: gptSuccess ? 'perplexity+gpt' : (prev.source || 'perplexity')
}}];

// S05-Claude: 교차검증 기반 최종 리포트 생성 (claude-sonnet-4-6)
const d = $input.first().json;
const { rawContent, gptContent, gptSuccess, perpSuccess,
        today, obsidianFilePath, backupFilePath, startTime, usdKrw, btcUsd } = d;
const KEY = $env.CLAUDE_API_KEY;

if (!KEY || KEY.includes('여기에')) {
  return [{ json: {
    ...d, success: false, source: 'claude',
    error: 'CLAUDE_API_KEY 미설정', rewrittenContent: null
  }}];
}

const systemPrompt = '당신은 한국 증권사 리서치센터 수석 애널리스트다.\nPerplexity(팩트·출처)와 GPT(인과관계·해석)의 리서치 초안을 받아 통합 데일리 리포트를 작성한다.\n\n[교차검증 규칙]\n1. 공통 사실 → 확정 서술\n2. Perplexity만 언급 → 출처 기반 참고, URL 병기\n3. GPT만 언급 → 추정/시나리오로 conditional 서술\n4. 상충 → 양측 병기, 신뢰도 높은 쪽 우선\n5. 과장·단정 → "~할 수 있다/가능성" 으로 완화\n\n[리포트 구조]\n1. 전일 미 증시 요약 (표)\n2. 핵심 변화요인\n3. 섹터·테마별 동향\n4. 한국 증시 시사점\n5. FICC\n6. 교차분석 코멘트\n7. 오늘의 체크포인트 (bullet 3개)\n\n[형식] 한국어, 증권사 문체, Markdown, 최소 3500자';

const parts = [];
if (perpSuccess && rawContent) {
  parts.push('=== PERPLEXITY SONAR-PRO (팩트·출처) ===\n' + rawContent);
}
if (gptSuccess && gptContent) {
  parts.push('=== GPT-4o (인과관계·해석) ===\n' + gptContent);
}
if (parts.length === 0) {
  return [{ json: {
    ...d, success: false, source: 'claude',
    error: '리서치 데이터 없음', rewrittenContent: null
  }}];
}

const userContent = '날짜: ' + today + ' | USD/KRW: ' + usdKrw + ' | BTC: ' + btcUsd + '\n\n' + parts.join('\n\n') + '\n\n위 초안을 교차검증하여 통합 데일리 리포트를 작성해주세요.';

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': KEY,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 8000,
      system: systemPrompt,
      messages: [{ role: 'user', content: userContent }]
    }),
    timeout: 90000
  });

  const r = typeof response === 'string' ? JSON.parse(response) : response;
  const report = r?.content?.[0]?.text;
  if (!report) throw new Error('Claude 응답 비어있음');

  return [{ json: {
    ...d,
    success: true,
    source: 'claude',
    rewrittenContent: report,
    model: r.model,
    llmModel: r.model,
    newsSource: gptSuccess ? 'perplexity+gpt+claude' : 'perplexity+claude'
  }}];
} catch(e) {
  return [{ json: {
    ...d, success: false, source: 'claude',
    error: e.message, rewrittenContent: null
  }}];
}

// ============================================================
// 노드 10: Llama3.1:8B Fallback — Qwen 실패 시 대체
// 모두 실패 시: 원문(영문) 그대로 저장 (최후 수단)
// ============================================================
const prev = $input.first().json;
const { rawContent, today, obsidianFilePath, backupFilePath, startTime, newsSource } = prev;
const HOST = 'http://127.0.0.1:11434';
const pass = { today, obsidianFilePath, backupFilePath, startTime, newsSource, rawContent };

try {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `${HOST}/api/generate`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'llama3.1:8b',
      // Llama3용 special token 형식
      prompt: `<|begin_of_text|><|start_header_id|>system<|end_header_id|>\n당신은 금융 전문 한국어 번역가입니다. 비존댓말(~다)로 작성하세요.<|eot_id|>\n<|start_header_id|>user<|end_header_id|>\n오늘(${today}) 금융 뉴스 한국어 브리핑:\n\n${rawContent}\n\n형식:\n### 🌐 글로벌 시장\n### 🇰🇷 국내 시장\n### 📈 ETF 동향\n### 💡 핵심 포인트<|eot_id|>\n<|start_header_id|>assistant<|end_header_id|>\n`,
      stream: false,
      options: { temperature: 0.3, num_predict: 2500 }
    }),
    timeout: 150000
  });

  const rewritten = r.response;
  if (!rewritten || rewritten.trim().length < 100) throw new Error('Llama 응답 없음');

  return [{ json: { ...pass, success: true, source: 'llama', model: 'llama3.1:8b', rewrittenContent: rewritten } }];

} catch(e) {
  // 로컬 LLM 전부 실패 → 원문(영문) 그대로 저장
  const fallback = `## 🚨 자동 번역 실패 — 원문 표시\n\n> Qwen·Llama 모두 실패. Ollama 상태 확인 후 수동 변환 필요.\n\n---\n\n${rawContent}`;
  return [{ json: { ...pass, success: true, source: 'raw_fallback', model: 'none', rewrittenContent: fallback } }];
}

// ============================================================
// 노드 11: 최종 마크다운 생성
// Obsidian YAML frontmatter + 브리핑 본문 + 생성정보 푸터
// 도착 경로: 노드9(TRUE) / 노드10(Llama) / 노드7(캐시)
// ============================================================
const data = $input.first().json;
const { today, obsidianFilePath, backupFilePath, startTime } = data;
const rewrittenContent = data.rewrittenContent;
const newsSource = data.newsSource || data.source || 'unknown';
const llmModel    = data.model || data.llmModel || 'unknown';

const endTime = new Date();
const durationSec = startTime
  ? Math.round((endTime - new Date(startTime)) / 1000)
  : 0;

const [year, month] = today.split('-');
const monthMap = {
  '01':'1월','02':'2월','03':'3월','04':'4월','05':'5월','06':'6월',
  '07':'7월','08':'8월','09':'9월','10':'10월','11':'11월','12':'12월'
};

// YAML frontmatter (Obsidian 메타데이터)
const fm = [
  '---',
  `title: "${today} 경제브리핑"`,
  `date: ${today}`,
  'tags:',
  '  - 경제브리핑',
  `  - ${year}년`,
  `  - ${monthMap[month] || month + '월'}`,
  '  - 자동생성',
  'category: 경제브리핑',
  `source: ${newsSource}`,
  `llm_model: ${llmModel}`,
  `created: ${endTime.toISOString()}`,
  `duration_sec: ${durationSec}`,
  '---',
  ''
].join('\n');

const header = [
  `# 📊 ${today} 경제브리핑`,
  '',
  `> **자동생성** | 뉴스: ${newsSource} → LLM: ${llmModel} | 소요: ${durationSec}초`,
  '',
  '---',
  ''
].join('\n');

const footer = [
  '',
  '---',
  '',
  '## 📝 생성 정보',
  '| 항목 | 값 |',
  '|------|---|',
  `| 날짜 | ${today} |`,
  `| 뉴스 소스 | ${newsSource} |`,
  `| LLM 모델 | ${llmModel} |`,
  `| 생성 시각 | ${endTime.toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' })} |`,
  `| 소요 시간 | ${durationSec}초 |`,
  '',
  '*WEGO 자동화 시스템으로 생성되었습니다.*'
].join('\n');

const finalMarkdown = fm + header + rewrittenContent + footer;

return [{ json: {
  finalMarkdown, today, obsidianFilePath, backupFilePath,
  wordCount: finalMarkdown.length, newsSource, llmModel, durationSec, startTime
}}];

// ============================================================
// 노드 12: Obsidian Vault 파일 저장
// 경로: OBSIDIAN_VAULT_PATH\경제브리핑\2026-03-04.md
// 실패 시: C:\temp\wego-backup-날짜.md 자동 백업
// ============================================================
const fs   = require('fs');
const path = require('path');
const data = $input.first().json;
const { finalMarkdown, obsidianFilePath, backupFilePath } = data;

if (!obsidianFilePath) {
  return [{ json: { ...data, saveSuccess: false,
    saveError: 'obsidianFilePath 없음 — 날짜 변수 세팅 노드 확인' } }];
}

try {
  // 폴더 없으면 자동 생성
  const dir = path.dirname(obsidianFilePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

  // 파일 저장
  fs.writeFileSync(obsidianFilePath, finalMarkdown, 'utf8');

  // 저장 검증
  const stats = fs.statSync(obsidianFilePath);
  if (stats.size < 200) throw new Error(`파일 크기 이상: ${stats.size}bytes`);

  return [{ json: {
    ...data, saveSuccess: true, savedPath: obsidianFilePath,
    fileSizeBytes: stats.size, saveTime: new Date().toISOString()
  }}];

} catch(mainErr) {
  // 메인 저장 실패 → C:\temp 백업
  try {
    const tempDir = path.dirname(backupFilePath);
    if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });
    fs.writeFileSync(backupFilePath, finalMarkdown, 'utf8');
    return [{ json: {
      ...data, saveSuccess: false, saveError: mainErr.message,
      backupSaved: true, savedPath: backupFilePath
    }}];
  } catch(backupErr) {
    return [{ json: {
      ...data, saveSuccess: false, saveError: mainErr.message,
      backupSaved: false, backupError: backupErr.message
    }}];
  }
}

// ============================================================
// 노드 14: Telegram 전문 분할 전송
// Telegram 4096자 제한 → 섹션별 분할 전송
// 헤더 + 본문 여러 메시지로 순차 전송
// ============================================================
const data  = $input.first().json;
const TOKEN = $env.TELEGRAM_BOT_TOKEN;
const CHAT  = $env.TELEGRAM_CHAT_ID;

if (!TOKEN || TOKEN.includes('여기에')) {
  return [{ json: { ...data, telegramSent: false, telegramNote: 'Telegram 봇 미설정 — 건너뜀' } }];
}

const MAX = 3800; // Telegram 4096자 제한, 여유분 확보
const sizeKB = Math.round((data.fileSizeBytes || 0) / 1024 * 10) / 10;

// 헤더 메시지 (요약)
const header =
  `📊 *[WEGO] ${data.today} 경제브리핑*\n` +
  `${'━'.repeat(28)}\n` +
  `📰 수집: ${data.newsSource} | 🤖 번역: ${data.llmModel}\n` +
  `📁 ${sizeKB}KB | ⏱ ${data.durationSec}초\n` +
  `${'━'.repeat(28)}`;

// 본문에서 YAML frontmatter 및 생성정보 제거 후 순수 내용만 추출
const raw = data.finalMarkdown || '';
const bodyStart = raw.indexOf('---\n', 4); // 두 번째 --- 이후
const bodyEnd   = raw.indexOf('## 📝 생성 정보');
let body = bodyStart > 0
  ? raw.slice(bodyStart + 4, bodyEnd > 0 ? bodyEnd : undefined).trim()
  : raw.trim();

// 섹션별 분할 (### 기준)
const sectionRegex = /(###[^\n]*\n)/g;
const parts = body.split(sectionRegex).filter(p => p.trim());

// 청크 생성: MAX자 이하로 묶기
const chunks = [];
let cur = '';
for (const part of parts) {
  if ((cur + part).length > MAX) {
    if (cur.trim()) chunks.push(cur.trim());
    cur = part;
  } else {
    cur += part;
  }
}
if (cur.trim()) chunks.push(cur.trim());

// 전체 메시지 배열 (헤더 + 청크들)
const messages = [header, ...chunks];

// 순차 전송
let sent = 0, failed = 0;
for (let i = 0; i < messages.length; i++) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.telegram.org/bot${TOKEN}/sendMessage`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: CHAT,
        text: messages[i],
        parse_mode: 'Markdown',
        disable_web_page_preview: true
      }),
      timeout: 8000
    });
    sent++;
    // 메시지 간 500ms 딜레이 (Telegram rate limit 방지)
    if (i < messages.length - 1) {
      await new Promise(r => setTimeout(r, 500));
    }
  } catch(e) {
    failed++;
  }
}

return [{ json: {
  ...data,
  telegramSent: sent > 0,
  telegramMessages: sent,
  telegramFailed: failed
}}];

