// ============================================================
// 노드 16: 실행 로그 기록
// 저장: OBSIDIAN_VAULT_PATH\wego-automation-logs.json
// SQLite 대신 JSON 파일 사용 (추가 설치 불필요)
// 최근 90일치 순환 보관
// ============================================================
const fs   = require('fs');
const path = require('path');
const data = $input.first().json;
const vaultPath = $env.OBSIDIAN_VAULT_PATH || 'D:\\Obsidian';
const logFile   = path.join(vaultPath, 'wego-automation-logs.json');

const entry = {
  timestamp:     new Date().toISOString(),
  date:          data.today,
  workflow:      'daily-economic-briefing',
  status:        data.saveSuccess ? 'success' : 'partial_fail',
  newsSource:    data.newsSource || 'unknown',
  llmModel:      data.llmModel   || 'unknown',
  saveSuccess:   !!data.saveSuccess,
  backupSaved:   !!data.backupSaved,
  telegramSent:  !!data.telegramSent,
  durationSec:   data.durationSec   || 0,
  fileSizeBytes: data.fileSizeBytes || 0,
  errors: {
    saveError:     data.saveError    || null,
    telegramError: data.telegramError || null
  }
};

try {
  let logs = [];
  if (fs.existsSync(logFile)) {
    try { logs = JSON.parse(fs.readFileSync(logFile, 'utf8')); } catch(e) {}
    if (!Array.isArray(logs)) logs = [];
  }

  logs.push(entry);

  // 최근 90개 유지 (90일치)
  if (logs.length > 90) logs = logs.slice(logs.length - 90);

  const dir = path.dirname(logFile);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(logFile, JSON.stringify(logs, null, 2), 'utf8');

} catch(e) { /* 로그 실패는 무시 — 워크플로 중단 안 함 */ }

return [{ json: { ...data, logEntry: entry, workflowComplete: true } }];

// S05b-Gemini: Claude 실패 시 폴백 — Gemini 3.1 Pro
const prev = $input.first().json;
const { rawContent, gptContent, today, obsidianFilePath, backupFilePath,
        startTime, usdKrw, btcUsd, newsSource } = prev;
const KEY = $env.GEMINI_API_KEY;

if (!KEY || KEY.includes('여기에')) {
  return [{ json: { ...prev, success: false, source: 'gemini',
    error: 'GEMINI_API_KEY 미설정', rewrittenContent: null } }];
}

const systemInstruction = '당신은 한국 증권사 리서치센터 수석 애널리스트입니다. '
  + 'Perplexity(팩트·출처)와 GPT(인과관계·해석)의 리서치를 통합 데일리 리포트로 작성하세요.\n\n'
  + '[리포트 구조] 1.전일 미 증시 요약(표) 2.핵심 변화요인 3.섹터·테마별 동향 '
  + '4.한국 증시 시사점 5.FICC 요약 6.리스크·기회 체크포인트 3가지\n'
  + '[형식] 한국어, 증권사 문체, Markdown, 최소 3500자';

const parts = [];
if (rawContent) parts.push('## Perplexity 리서치\n' + rawContent);
if (gptContent) parts.push('## GPT 분석\n' + gptContent);
if (!parts.length) {
  return [{ json: { ...prev, success: false, source: 'gemini',
    error: '리서치 데이터 없음', rewrittenContent: null } }];
}
const userPrompt = '날짜: ' + today + ' | USD/KRW: ' + usdKrw + ' | BTC: ' + btcUsd
  + '\n\n' + parts.join('\n\n') + '\n\n통합 데일리 리포트를 작성하세요.';

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-3.1-pro-preview:generateContent?key=' + KEY,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      system_instruction: { parts: [{ text: systemInstruction }] },
      contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
      generationConfig: { temperature: 0.3, maxOutputTokens: 8192 }
    }),
    timeout: 90000
  });
  const r = typeof response === 'string' ? JSON.parse(response) : response;
  const report = r?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!report) throw new Error('Gemini 응답 비어있음');
  return [{ json: {
    ...prev, success: true, source: 'gemini', rewrittenContent: report,
    llmModel: 'gemini-3.1-pro-preview', newsSource: newsSource || 'perplexity'
  } }];
} catch(e) {
  return [{ json: { ...prev, success: false, source: 'gemini',
    error: e.message, rewrittenContent: null } }];
}
